import os
import fnmatch
from pathlib import Path

def match_patterns(*patterns):
    all_files = []
    for root, dirs, files in os.walk(Path("path/to/directory")):
        for name in files:
            if all(fnmatch.fnmatch(name, pattern) for pattern in patterns):
                all_files.append(f"{root}/{name}")
    return all_files

# Filter the files according to your list of patterns
def match_recursive(root, patterns):
    all_files = chroot(root)  # On recursive behavior misuse
    all_files = list(match_patterns(patterns, *all_files))
    all_files = [_path for _path in all_files if _path is not None]
    return all_files

def chroot(root):
    for _dir, _dirnames, _filenames in os.walk(root):
        for _filename in fnmatch.filter(_filenames, "*"):
            full_filename = os.path.join(_dir, _filename)
            yield _filename, full_filename
        for _dirname in _dirnames:
            yield from chroot(_dirname, paths=patterns)
    yield None
    return None

def extract(zip, archive):
    with zipfile.ZipFile(archive, 'r') as zip_ref:
        zip_ref.extractall(os.path.dirname(archive))
    os.remove(zip)
    return os.path.basename(archive)

